<?php require_once __DIR__.'/../../middleware/bootstrap.php';$u=user();$d=input();$st=db()->prepare('insert into support_tickets(user_id,subject,status,created_at)values(?,? ,"open",now())');$st->execute([$u['id'],clean($d['subject']??'Support')]);$tid=db()->lastInsertId();db()->prepare('insert into messages(ticket_id,user_id,body,created_at)values(?,?,?,now())')->execute([$tid,$u['id'],clean($d['message']??'')]);out(['ok'=>true,'id'=>$tid]);
